import { WorkflowContext } from 'mastra';

const validateWorkflowContext = (ctx: WorkflowContext): boolean => {
  const requiredFields = ['agentId', 'stepId', 'sessionId', 'output'];
  const missing = requiredFields.filter(field => !ctx[field]);

  if (missing.length > 0) {
    console.error('❌ WorkflowContext missing fields:', missing);
    return false;
  }

  // Check output schema compliance
  if (ctx.output && typeof ctx.output !== 'object') {
    console.error('❌ Invalid output structure:', ctx.output);
    return false;
  }

  return true;
};

// Hook into Mastra workflow transitions
workflow.onTransition((fromCtx, toCtx) => {
  if (!validateWorkflowContext(toCtx)) {
    throw new Error('Workflow coordination failure detected');
  }
});

import { z } from 'zod';
import { AgentToolCall } from 'mastra/agent';

const toolResponseSchema = z.object({
  success: z.boolean(),
  data: z.record(z.unknown()),
  error: z.string().optional()
});

const monitorToolCalls = (toolCall: AgentToolCall): void => {
  const result = toolResponseSchema.safeParse(toolCall.result);

  if (!result.success) {
    console.error('🔥 Tool response validation failed:', {
      tool: toolCall.toolName,
      errors: result.error.errors,
      rawResult: toolCall.result
    });

    // Flag coordination failure
    toolCall.metadata = { ...toolCall.metadata, vexIssue: 'malformed-tool-response' };
  }
};

agent.onToolCall(monitorToolCalls);

import { MemoryEntry, KnowledgeBase } from 'mastra/memory';

const STALE_THRESHOLD_MS = 5 * 60 * 1000; // 5 minutes

const detectStaleContext = (memory: MemoryEntry[]): boolean => {
  const now = Date.now();
  const staleEntries = memory.filter(entry => 
    now - new Date(entry.timestamp).getTime() > STALE_THRESHOLD_MS
  );

  if (staleEntries.length > 0) {
    console.warn('⚠️ Stale memory detected:', {
      count: staleEntries.length,
      oldest: staleEntries[0].timestamp,
      keys: staleEntries.map(e => e.key)
    });
    return true;
  }

  return false;
};

knowledgeBase.onRetrieve((entries) => {
  if (detectStaleContext(entries)) {
    throw new Error('Multi-agent coordination failure: stale context');
  }
});

