import { WorkflowContext, Workflow } from 'mastra';

const contextGuard = (ctx: WorkflowContext): WorkflowContext => {
  const validators = {
    agentId: (v: any) => typeof v === 'string',
    stepId: (v: any) => typeof v === 'string',
    output: (v: any) => v && typeof v === 'object'
  };

  for (const [field, validator] of Object.entries(validators)) {
    if (!validator(ctx[field])) {
      throw new Error(`Invalid ${field} in workflow context`);
    }
  }

  return ctx;
};

const safeWorkflow = new Workflow({
  transitions: {
    validate: (ctx) => contextGuard(ctx),
    // ... other transitions
  }
});

import { Agent, ToolResponse } from 'mastra/agent';
import { z } from 'zod';

const TOOL_SCHEMA = z.object({
  success: z.boolean().default(false),
  data: z.record(z.unknown()).default({}),
  error: z.string().optional()
});

const normalizeToolResponse = (raw: any): ToolResponse => {
  const parsed = TOOL_SCHEMA.parse(raw);

  return {
    ...parsed,
    metadata: {
      normalized: true,
      originalShape: raw,
      timestamp: Date.now()
    }
  };
};

const robustAgent = new Agent({
  tools: {
    call: async (toolName, params) => {
      const rawResult = await callTool(toolName, params);
      return normalizeToolResponse(rawResult);
    }
  }
});

import { KnowledgeBase } from 'mastra/memory';

const FRESHNESS_WINDOW_MS = 5 * 60 * 1000;

const freshContextFilter = (entries: MemoryEntry[]): MemoryEntry[] => {
  const now = Date.now();
  return entries.filter(entry => 
    now - new Date(entry.timestamp).getTime() < FRESHNESS_WINDOW_MS
  );
};

const reliableKnowledgeBase = new KnowledgeBase({
  retrieve: async (query) => {
    const allEntries = await this.storage.retrieve(query);
    const freshEntries = freshContextFilter(allEntries);

    if (freshEntries.length !== allEntries.length) {
      console.log(`Filtered ${allEntries.length - freshEntries.length} stale entries`);
    }

    return freshEntries;
  }
});

