import { Vex } from '@vex_dev/sdk';
import { MastraWorkflow, Agent } from 'mastra';

// Initialize Vex middleware for Mastra
const vex = new Vex({
  projectId: 'your-project-id',
  autoRemediate: true,
  failureTypes: ['coordination', 'schema', 'stale-context']
});

// Single-line integration into Mastra workflow
const monitoredWorkflow = new MastraWorkflow({
  middleware: [vex.mastraMiddleware()],
  agents: [
    new Agent({
      name: 'coordinator',
      vexMonitor: true  // Auto-detects coordination failures
    })
  ]
});

// Vex auto-generates reliability dashboard and alerts
vex.on('coordinationFailure', (issue) => {
  console.log('🛑 Auto-detected:', issue.type, issue.severity);
  vex.applyFix(issue.recommendedFix);
});
